// Time:  O(m * n * k)
// Space: O(m * n * k)

// dp
class Solution {
public:
    int maxPathScore(vector<vector<int>>& grid, int k) {
        static const vector<pair<int, int>> DIRECTIONS = {{1, 0}, {0, 1}};

        vector<vector<vector<int>>> dp(size(grid), vector<vector<int>>(size(grid[0]), vector<int>(k + 1, -1)));
        dp[0][0][0] = 0;
        for (int i = 0; i < size(grid); ++i) {
            for (int j = 0; j < size(grid[0]); ++j) {
                for (int c = 0; c <= k; ++c) {
                    if (dp[i][j][c] == -1) {
                        continue;
                    }
                    for (const auto& [di, dj] : DIRECTIONS) {
                        const int ni = i + di;
                        const int nj = j + dj;
                        if (!(0 <= ni && ni < size(grid) &&
                              0 <= nj && nj < size(grid[0]) &&
                              c + (grid[ni][nj] ? 1 : 0) <= k)) {
                            continue;
                        }
                        const int nc = c + (grid[ni][nj] ? 1 : 0);
                        dp[ni][nj][nc] = max(dp[ni][nj][nc] , dp[i][j][c] + grid[ni][nj]);
                    }
                }
            }
        }
        return ranges::max(dp.back().back());
    }
};

# Time:  O(m * n * k)
# Space: O(m * n * k)

# dp
class Solution(object):
    def maxPathScore(self, grid, k):
        """
        :type grid: List[List[int]]
        :type k: int
        :rtype: int
        """
        DIRECTIONS = ((1, 0), (0, 1))
        dp = [[[-1]*(k+1) for _ in xrange(len(grid[0]))] for _ in xrange(len(grid))]
        dp[0][0][0] = 0
        for i in xrange(len(grid)):
            for j in xrange(len(grid[0])):
                for c in xrange(k+1):
                    if dp[i][j][c] == -1:
                        continue
                    for di, dj in DIRECTIONS:
                        ni, nj = i+di, j+dj
                        if not (0 <= ni < len(grid) and 0 <= nj < len(grid[0]) and c+(1 if grid[ni][nj] else 0) <= k):
                            continue
                        nc = c+(1 if grid[ni][nj] else 0)
                        dp[ni][nj][nc] = max(dp[ni][nj][nc] , dp[i][j][c]+grid[ni][nj])
        return max(dp[-1][-1])
